// envelope shape: { gatewayId, clusterId, frameHex, frameLen, rssi, snr, parseStatus }
const gldDecode = global.get('gldDecode');
const keysById = global.get('gldKeysById') || {};

if (!msg.payload || !msg.payload.frameHex) {
    node.warn('uplink message missing frameHex, dropping');
    return null;
}

const events = gldDecode.decodeGatewayFrame(msg.payload, keysById);
return events.map((event) => ({ payload: event }));

const event = msg.payload;

if (!event || event.ok === false) {
    msg.topic = 'gld/gateway/error';
} else if (event.alarm === true) {
    msg.topic = 'gld/server/alarm';
} else {
    msg.topic = 'gld/server/decoded';
}

return msg;
